echo "=== Languages across ALL xcstrings (real translations) ===" && python3 -c "
import json, glob
langs = {}
for f in glob.glob('iosApp/**/*.xcstrings', recursive=True):
    d = json.load(open(f))
    for k, v in d.get('strings', {}).items():
        for lang in v.get('localizations', {}).keys():
            langs[lang] = langs.get(lang, 0) + 1
print('lang -> total localized strings:')
for l, c in sorted(langs.items(), key=lambda x:-x[1]):
    print('   ', l, c)
"
echo
echo "=== Sample: Dose.xcstrings first 3 keys with translations ==="
python3 -c "
import json
d = json.load(open('iosApp/RadiaCode/Resources/Localization/Dose.xcstrings'))
print('sourceLanguage:', d.get('sourceLanguage'))
for k in list(d['strings'].keys())[:3]:
    print('KEY:', repr(k))
    for lang, val in d['strings'][k].get('localizations', {}).items():
        # could be stringUnit or variations (plural)
        if 'stringUnit' in val:
            print('   ', lang, '->', repr(val['stringUnit'].get('value')))
        elif 'variations' in val:
            print('   ', lang, '-> [plural variations]', json.dumps(val['variations'], ensure_ascii=False)[:200])
"

